ee:variables.ee:set-variable:
%dw 2.0

output application/java

var body = if (payload.Envelope?) payload.Envelope.Body else if (payload.body?) payload.body else payload

var r = if (payload.sourceSystem?)

  payload

else

  body.ObtenerContenidosExternosRequest default body.*ObtenerContenidosExternosRequest[0] default {}

---

{

  sourceSystem: (r.sourceSystem default "legacy-lms") as String,

  catalogId: r.catalogId as String default null,

  modifiedSince: r.modifiedSince as DateTime default null

}

db:select.db:input-parameters:
#[{

  sistema: vars.req.sourceSystem,

  catalogId: vars.req.catalogId,

  modifiedSince: vars.req.modifiedSince

}]

ee:message.ee:set-payload:
%dw 2.0

output application/java

ns ns0 http://mtis.ua.es/elearning/legacy

fun asXmlDateTime(v) =

  if (v == null) null

  else (v as DateTime) as String { format: "yyyy-MM-dd'T'HH:mm:ss" }

fun toContent(row) = {

  ns0#externalContentId: row.external_content_id,

  ns0#title: row.titulo,

  ns0#description: row.descripcion,

  ns0#category: row.categoria,

  ns0#lastModified: asXmlDateTime(row.ultima_modificacion),

  ns0#checksum: row.checksum

}

---

{

  body: {

    ns0#ObtenerContenidosExternosResponse: {

      ns0#sourceSystem: vars.req.sourceSystem,

      ns0#contents: (payload default []) map toContent($)

    }

  } write "application/xml"

}

%dw 2.0

output application/java

ns ns0 http://mtis.ua.es/elearning/legacy

var finished = now()

---

{

  body: {

    ns0#SincronizarDatosRepositorioResponse: {

      ns0#syncId: vars.syncId,

      ns0#status: "SUCCESS",

      ns0#processedItems: vars.syncTotal,

      ns0#updatedItems: vars.syncTotal,

      ns0#failedItems: 0,

      ns0#startedAt: (vars.syncStarted as DateTime) as String { format: "yyyy-MM-dd'T'HH:mm:ss" },

      ns0#finishedAt: (finished as DateTime) as String { format: "yyyy-MM-dd'T'HH:mm:ss" },

      ns0#message: "Sincronizacion del repositorio legacy completada (" ++ vars.syncTotal ++ " contenidos)"

    }

  } write "application/xml"

}

ee:variables.ee:set-variable:
%dw 2.0

output application/java

var body = if (payload.Envelope?) payload.Envelope.Body else if (payload.body?) payload.body else payload

var r = if (payload.externalContentId? or payload.sourceSystem?)

  payload

else

  body.ConsultarMetadatosContenidoRequest default body.*ConsultarMetadatosContenidoRequest[0] default {}

---

{

  sourceSystem: (r.sourceSystem default "legacy-lms") as String,

  externalContentId: (r.externalContentId default "") as String

}

ee:message.ee:set-payload:
%dw 2.0

output application/java

ns ns0 http://mtis.ua.es/elearning/legacy

var row = payload[0]

---

{

  body: {

    ns0#ConsultarMetadatosContenidoResponse: {

      ns0#metadata: {

        ns0#externalContentId: row.external_content_id,

        ns0#title: row.titulo,

        ns0#description: row.descripcion,

        ns0#category: row.categoria,

        ns0#lastModified: if (row.ultima_modificacion == null) null

          else (row.ultima_modificacion as DateTime) as String { format: "yyyy-MM-dd'T'HH:mm:ss" },

        ns0#checksum: row.checksum

      }

    }

  } write "application/xml"

}
